import React, { createContext, useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import { onSnapshot, doc } from 'firebase/firestore';
import { db } from '../firebase';
import { solvers as solverCatalog } from '../solverCatalog/solverDefinitions';

const API_MODE = process.env.REACT_APP_API_MODE || 'firebase';

export const SessionContext = createContext();

export const SessionProvider = ({ children }) => {
  const [session, setSession] = useState(null);
  const [solvers, setSolvers] = useState(solverCatalog);
  const [loading, setLoading] = useState(true);
  const [recommendation, setRecommendation] = useState(null);
  const [execution, setExecution] = useState(null);
  const [result, setResult] = useState(null);
  const location = useLocation();
  const navigate = useNavigate();

  const resetState = () => {
    setSession(null);
    setRecommendation(null);
    setExecution(null);
    setResult(null);
    setLoading(false);
  }

  const getResult = async (resultId) => {
    if (!resultId) return null;
    const resultDoc = await getDoc(doc(db, "results", resultId));
    return resultDoc.exists() ? { id: resultDoc.id, ...resultDoc.data() } : null;
  }

  // This effect handles loading a session from a URL
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const sessionId = params.get('session');

    if (sessionId) {
        if (!session || session.id !== sessionId) {
            setLoading(true);
            api.getSession(sessionId)
                .then(sessionData => {
                    if (sessionData) {
                      setSession({ id: sessionId, ...sessionData });

                      if (sessionData.recommendationId) {
                          api.getRecommendation(sessionData.recommendationId).then(setRecommendation);
                      }
                      if (sessionData.resultId) {
                          getResult(sessionData.resultId).then(setResult);
                      }
                    }
                })
                .catch(err => {
                    console.error("Failed to load session:", err);
                    resetState();
                })
                .finally(() => setLoading(false));
        }
    } else {
        resetState();
    }
  }, [location.search]); // Removed session dependency to avoid re-running

  // This effect sets up a real-time listener for the current session document
  useEffect(() => {
    if (session?.id && API_MODE === 'firebase') {
      const unsubscribe = onSnapshot(doc(db, "sessions", session.id), (doc) => {
        if (doc.exists()) {
          console.log("Real-time session update:", doc.data());
          const sessionData = doc.data();
          setSession(prev => ({ ...prev, ...sessionData }));

          // If a result ID appears, fetch the result data
          if (sessionData.resultId && (!result || result.id !== sessionData.resultId)) {
            getResult(sessionData.resultId).then(setResult);
          }
        } 
      });

      // Cleanup listener on unmount or session change
      return () => unsubscribe();
    }
  }, [session?.id]);

  // This effect sets up a real-time listener for the current session's execution data
  useEffect(() => {
    if (session?.executionId && API_MODE === 'firebase') {
      const unsubscribe = onSnapshot(doc(db, "executions", session.executionId), (doc) => {
        if (doc.exists()) {
          console.log("Real-time execution update:", doc.data());
          setExecution({ id: doc.id, ...doc.data() });
        } else {
          setExecution(null);
        }
      });

      // Cleanup listener on unmount or session change
      return () => unsubscribe();
    }
  }, [session?.executionId]);

  const startNewSession = useCallback(async (goal) => {
    if (!goal) return;
    setLoading(true);
    try {
        const { sessionId } = await api.createSession({ goal });
        navigate(`/job-configuration?session=${sessionId}`);
    } catch (error) {
        console.error("Error starting new session:", error);
        throw error;
    } finally {
        setLoading(false);
    }
  }, [navigate]);

  const generateRecommendation = useCallback(async (sessionId) => {
    if (!sessionId) return;
    try {
      const rec = await api.generateRecommendation(sessionId);
      setRecommendation(rec);
      setSession(prev => ({...prev, status: 'analyzed', currentStage: 'method'}));
      return rec;
    } catch (error) {
      console.error("Error generating recommendation:", error);
      throw error;
    }
  }, []);


  const value = { 
    session, 
    solvers,
    loading, 
    startNewSession, 
    recommendation, 
    generateRecommendation,
    execution, 
    result
  };

  return (
    <SessionContext.Provider value={value}>
      {children}
    </SessionContext.Provider>
  );
};
